<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Bouncing Ball Physics Playground</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #1a1a2e;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    font-family: 'Segoe UI', system-ui, sans-serif;
    color: #e0e0e0;
  }
  h1 {
    margin-bottom: 16px;
    font-size: 1.4rem;
    letter-spacing: 1px;
    color: #a8d8ea;
  }
  #sim {
    border: 2px solid #333;
    border-radius: 8px;
    background: #0f0f23;
    cursor: crosshair;
    display: block;
    width: 600px;
    height: 450px;
    max-width: 95vw;
    max-height: 70vh;
  }
  .controls {
    margin-top: 16px;
    display: flex;
    gap: 12px;
  }
  button {
    padding: 10px 24px;
    border: none;
    border-radius: 6px;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background 0.2s, transform 0.1s;
    font-weight: 600;
  }
  button:active { transform: scale(0.96); }
  #drop { background: #e94560; color: #fff; }
  #drop:hover { background: #ff6b81; }
  #play { background: #0f3460; color: #a8d8ea; border: 1px solid #a8d8ea; }
  #play:hover { background: #16213e; }
  #clear { background: #533483; color: #fff; }
  #clear:hover { background: #6c4a9e; }
</style>
</head>
<body>

<h1>🎱 Bouncing Ball Playground</h1>
<canvas id="sim" width="600" height="450"></canvas>
<div class="controls">
  <button id="drop">Drop Ball</button>
  <button id="play">Pause</button>
  <button id="clear">Clear All</button>
</div>

<script>
(function () {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');
  const dropBtn = document.getElementById('drop');
  const playBtn = document.getElementById('play');
  const clearBtn = document.getElementById('clear');

  const W = canvas.width;
  const H = canvas.height;
  const GRAVITY = 600;          // pixels/s²
  const RESTITUTION = 0.85;     // energy loss on bounce
  const FRICTION = 0.999;       // slight air friction

  let balls = [];
  let running = true;
  let animId = null;

  /* ---- helpers ---- */
  function randomColor() {
    const hues = [
      '#e94560','#ff6b81','#fca311','#ffd166',
      '#06d6a0','#1dd1a1','#48dbfb','#a8d8ea',
      '#c77dff','#e056a0'
    ];
    return hues[Math.floor(Math.random() * hues.length)];
  }

  function createBall(x, y, vx, vy, r) {
    return { x, y, vx: vx || 0, vy: vy || 0, r: r || (12 + Math.random() * 18), color: randomColor() };
  }

  /* ---- physics step ---- */
  function step(dt) {
    // dt is a multiplier; default 1 means one simulation tick
    const g = GRAVITY * dt;
    for (let i = 0; i < balls.length; i++) {
      const b = balls[i];

      // gravity
      b.vy += g;

      // air friction
      b.vx *= FRICTION;
      b.vy *= FRICTION;

      // integrate position
      b.x += b.vx * dt;
      b.y += b.vy * dt;

      // clamp & bounce — floor
      if (b.y + b.r > H) {
        b.y = H - b.r;
        b.vy = -Math.abs(b.vy) * RESTITUTION;
      }
      // ceiling
      if (b.y - b.r < 0) {
        b.y = b.r;
        b.vy = Math.abs(b.vy) * RESTITUTION;
      }
      // right wall
      if (b.x + b.r > W) {
        b.x = W - b.r;
        b.vx = -Math.abs(b.vx) * RESTITUTION;
      }
      // left wall
      if (b.x - b.r < 0) {
        b.x = b.r;
        b.vx = Math.abs(b.vx) * RESTITUTION;
      }
    }
  }

  /* ---- rendering ---- */
  function draw() {
    ctx.clearRect(0, 0, W, H);

    // subtle grid
    ctx.strokeStyle = 'rgba(255,255,255,0.03)';
    ctx.lineWidth = 1;
    for (let x = 0; x < W; x += 40) {
      ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, H); ctx.stroke();
    }
    for (let y = 0; y < H; y += 40) {
      ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(W, y); ctx.stroke();
    }

    // balls with glow
    for (const b of balls) {
      const grad = ctx.createRadialGradient(b.x - b.r * 0.3, b.y - b.r * 0.3, b.r * 0.1, b.x, b.y, b.r);
      grad.addColorStop(0, '#fff');
      grad.addColorStop(0.3, b.color);
      grad.addColorStop(1, shadeColor(b.color, -40));

      ctx.save();
      ctx.shadowColor = b.color;
      ctx.shadowBlur = 12;
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.fillStyle = grad;
      ctx.fill();
      ctx.restore();

      // highlight
      ctx.save();
      ctx.globalAlpha = 0.35;
      const hl = ctx.createRadialGradient(b.x - b.r * 0.25, b.y - b.r * 0.3, 1, b.x - b.r * 0.25, b.y - b.r * 0.3, b.r * 0.6);
      hl.addColorStop(0, '#fff');
      hl.addColorStop(1, 'transparent');
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.fillStyle = hl;
      ctx.fill();
      ctx.restore();
    }
  }

  function shadeColor(hex, percent) {
    const num = parseInt(hex.replace('#', ''), 16);
    const r = Math.min(255, Math.max(0, (num >> 16) + percent));
    const g = Math.min(255, Math.max(0, ((num >> 8) & 0x00ff) + percent));
    const b = Math.min(255, Math.max(0, (num & 0x0000ff) + percent));
    return '#' + (0x1000000 + r * 0x10000 + g * 0x100 + b).toString(16).slice(1);
  }

  /* ---- animation loop ---- */
  function loop() {
    if (running) {
      step(1);
      draw();
    }
    animId = requestAnimationFrame(loop);
  }

  /* ---- public API ---- */
  window.sim = {
    get w() { return W; },
    get h() { return H; },

    balls: function () {
      return balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r }));
    },

    addBall: function (x, y, vx, vy, r) {
      if (typeof vx === 'undefined') vx = 0;
      if (typeof vy === 'undefined') vy = 0;
      balls.push(createBall(x, y, vx, vy, r));
      draw();
    },

    clear: function () {
      balls = [];
      draw();
    },

    step: function (dt) {
      if (typeof dt === 'undefined') dt = 1;
      step(dt);
      draw();
    }
  };

  /* ---- UI events ---- */
  dropBtn.addEventListener('click', () => {
    const x = 80 + Math.random() * (W - 160);
    window.sim.addBall(x, 40, (Math.random() - 0.5) * 200, 0, 14 + Math.random() * 16);
  });

  playBtn.addEventListener('click', () => {
    running = !running;
    playBtn.textContent = running ? 'Pause' : 'Play';
  });

  clearBtn.addEventListener('click', () => {
    window.sim.clear();
  });

  canvas.addEventListener('click', (e) => {
    const rect = canvas.getBoundingClientRect();
    const scaleX = W / rect.width;
    const scaleY = H / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;
    window.sim.addBall(x, y, (Math.random() - 0.5) * 150, -100, 14 + Math.random() * 16);
  });

  /* ---- start ---- */
  loop();
})();
</script>
</body>
</html>
